mapper.select:
SELECT vt.id, vt.template_code, vt.template_name, vt.voucher_format, vt.company_id, vt.html_template, vt.css_styles, vt.description, vt.is_active, vt.is_default, vt.version, vt.supported_formats, vt.include_approval, vt.include_logo, vt.page_orientation, vt.paper_size, vt.margin_settings, vt.created_by, vt.created_at, vt.updated_at FROM voucher_templates vt WHERE vt.is_active = true AND ( vt.company_id IS NULL
OR vt.company_id = #{companyId}::uuid
)
AND vt.voucher_format = #{voucherFormat}
ORDER BY vt.is_default DESC, vt.company_id NULLS LAST, vt.created_at DESC

SELECT vt.id, vt.template_code, vt.template_name, vt.voucher_format, vt.company_id, vt.html_template, vt.css_styles, vt.description, vt.is_active, vt.is_default, vt.version, vt.supported_formats, vt.include_approval, vt.include_logo, vt.page_orientation, vt.paper_size, vt.margin_settings, vt.created_by, vt.created_at, vt.updated_at FROM voucher_templates vt
AND vt.company_id = #{companyId}::uuid
AND vt.is_active = #{isActive}
ORDER BY vt.is_default DESC, vt.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM voucher_templates vt
AND vt.company_id = #{companyId}::uuid
AND vt.is_active = #{isActive}

SELECT vt.id, vt.template_code, vt.template_name, vt.voucher_format, vt.company_id, vt.html_template, vt.css_styles, vt.description, vt.is_active, vt.is_default, vt.version, vt.supported_formats, vt.include_approval, vt.include_logo, vt.page_orientation, vt.paper_size, vt.margin_settings, vt.created_by, vt.created_at, vt.updated_at FROM voucher_templates vt WHERE vt.is_active = true AND vt.is_default = true AND vt.voucher_format = #{voucherFormat} AND ( vt.company_id IS NULL
OR vt.company_id = #{companyId}::uuid
) ORDER BY vt.company_id NULLS LAST LIMIT 1

mapper.update:
UPDATE voucher_templates 
SET is_active = #{isActive}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{templateId}

UPDATE voucher_templates 
SET is_default = #{isDefault}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{templateId}

mapper.select:
SELECT EXISTS(
    SELECT 1 FROM voucher_templates 
    WHERE template_code = #{templateCode}

        AND id != #{excludeId}

)

SELECT vt.voucher_format as format, COUNT(*) as total_count, COUNT(CASE WHEN vt.is_active = true THEN 1 END) as active_count, COUNT(CASE WHEN vt.is_default = true THEN 1 END) as default_count FROM voucher_templates vt WHERE ( vt.company_id IS NULL
OR vt.company_id = #{companyId}::uuid
) GROUP BY vt.voucher_format ORDER BY vt.voucher_format
